import{_ as r,o as n,c as o,a0 as s}from"./chunks/framework.DV6pVIgV.js";const p=JSON.parse('{"title":"雲端運算 EC2","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/2.md","filePath":"clf-c02/2.md","lastUpdated":1783610848000}'),a={name:"clf-c02/2.md"};function e(d,t,l,i,g,c){return n(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="雲端運算-ec2" tabindex="-1">雲端運算 EC2 <a class="header-anchor" href="#雲端運算-ec2" aria-label="Permalink to &quot;雲端運算 EC2&quot;">​</a></h1><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>虛擬機器（VM）與虛擬化</strong></p><ul><li><a href="https://glossary.cncf.io/zh-tw/virtualization/" target="_blank" rel="noreferrer">CNCF 雲端原生詞彙表：虛擬化</a></li><li><a href="https://aws.amazon.com/what-is/virtualization/" target="_blank" rel="noreferrer">AWS：What is Virtualization</a></li></ul></li><li><p><strong>連線（SSH／RDP）</strong></p><ul><li><a href="https://www.cloudflare.com/zh-tw/learning/access-management/what-is-ssh/" target="_blank" rel="noreferrer">Cloudflare：What is SSH</a></li><li><a href="https://medium.com/starbugs/security-%E4%BD%A0%E8%A9%B2%E7%9F%A5%E9%81%93%E6%89%80%E6%9C%89%E9%97%9C%E6%96%BC-ssh-%E7%9A%84%E9%82%A3%E4%BA%9B%E4%BA%8B-76b3518cb747" target="_blank" rel="noreferrer">你該知道所有關於 SSH 的那些事</a></li></ul></li><li><p><strong>連接埠（Port）</strong></p><ul><li><a href="https://www.cloudflare.com/learning/network-layer/what-is-a-computer-port/" target="_blank" rel="noreferrer">Cloudflare：What is a computer port</a></li></ul></li></ul><h2 id="amazon-ec2-是什麼" tabindex="-1">Amazon EC2 是什麼 <a class="header-anchor" href="#amazon-ec2-是什麼" aria-label="Permalink to &quot;Amazon EC2 是什麼&quot;">​</a></h2><p>EC2（Elastic Compute Cloud）提供「<strong>安全、可調整大小的雲端運算容量</strong>」——就是<strong>在雲上租一台虛擬伺服器</strong>。你可以在上面裝任何作業系統與軟體，跑網站、跑應用程式、跑資料庫。</p><p>對比傳統做法就懂它的價值：自建機房要先採購硬體、等貨到、上架、裝設定，動輒數週；EC2 <strong>幾分鐘就能開好一台</strong>，不用了就關掉、只付用到的時間（呼應雲端「變動支出取代固定支出」「提升速度與敏捷」）。</p><p><strong>怎麼運作（三步）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 啟動（Launch）：選一個 AMI（系統範本）＋ 選 instance type（硬體規格）</span></span>
<span class="line"><span>2. 連線（Connect）：用 SSH（Linux）或 RDP（Windows）連進去</span></span>
<span class="line"><span>3. 使用（Use）：裝軟體、跑你的應用</span></span></code></pre></div><blockquote><p>💡 同一台實體主機上，AWS 用<strong>虛擬化</strong>切出多台 EC2 給不同客戶，彼此<strong>隔離</strong>互不干擾。這就是「多租戶」——你感覺像獨佔一台機器，實際上是共享底層硬體。</p></blockquote><h2 id="ec2-執行個體類型" tabindex="-1">EC2 執行個體類型 <a class="header-anchor" href="#ec2-執行個體類型" aria-label="Permalink to &quot;EC2 執行個體類型&quot;">​</a></h2><p>AWS 依「<strong>強化哪一種硬體</strong>」把機器分成<strong>五大類別</strong>，讓你<strong>按工作的瓶頸挑機器</strong>。不必背型號，記住每一類強化什麼、適合什麼即可：</p><table tabindex="0"><thead><tr><th>類型</th><th>優化方向</th><th>適合場景</th></tr></thead><tbody><tr><td><strong>General Purpose（通用型）</strong></td><td>運算 / 記憶體 / 網路<strong>均衡</strong></td><td>網站、應用伺服器、中小型資料庫——不確定時的預設選擇</td></tr><tr><td><strong>Compute Optimized（運算優化）</strong></td><td>高 CPU</td><td>高效能運算（HPC）、批次處理、遊戲伺服器、ML 推論</td></tr><tr><td><strong>Memory Optimized（記憶體優化）</strong></td><td>大記憶體</td><td>大型記憶體內資料庫、即時處理大量資料</td></tr><tr><td><strong>Storage Optimized（儲存優化）</strong></td><td>高速本地儲存、高 IOPS</td><td>資料倉儲、分散式檔案系統、需要大量本地讀寫的工作</td></tr><tr><td><strong>Accelerated Computing（加速運算）</strong></td><td>GPU / 專用晶片</td><td>機器學習訓練、繪圖渲染、大量浮點運算</td></tr></tbody></table><blockquote><ul><li>看到「需要大量記憶體跑記憶體內資料庫」→ Memory Optimized；「機器學習訓練 / GPU」→ Accelerated Computing；「不確定 / 一般網站」→ General Purpose。</li><li>每個「類別」底下還有很多<strong>家族（family）與世代</strong>（如 m7i、c7g…），不必背型號，認得<strong>字首對應哪一類</strong>就好。</li></ul></blockquote><h2 id="開機前要懂的三個東西" tabindex="-1">開機前要懂的三個東西 <a class="header-anchor" href="#開機前要懂的三個東西" aria-label="Permalink to &quot;開機前要懂的三個東西&quot;">​</a></h2><ul><li><strong>AMI（Amazon Machine Image，系統映像）</strong> — 預先打包好的「<strong>作業系統 + 預裝軟體</strong>」範本。選 AMI 等於決定「這台機器一開機長什麼樣」（例如 Amazon Linux、Windows Server，或已裝好 WordPress 的映像）。</li><li><strong>Key Pair（金鑰對）</strong> — SSH 登入用的「<strong>鑰匙</strong>」。AWS 給你一個私鑰檔，連線時用它證明身分。<strong>務必保存好，弄丟無法重新下載。</strong></li><li><strong>Security Group（安全群組）</strong> — 這台 EC2 的<strong>防火牆</strong>（呼應先備知識）。預設把連入流量全擋掉，你要<strong>手動開放需要的 port</strong>（SSH 22、HTTP 80）。</li></ul><h2 id="執行個體狀態與生命週期" tabindex="-1">執行個體狀態與生命週期 <a class="header-anchor" href="#執行個體狀態與生命週期" aria-label="Permalink to &quot;執行個體狀態與生命週期&quot;">​</a></h2><p>開好的 EC2 不是只有「開」和「刪」，幾個動作的差別直接關係到<strong>會不會繼續被收費</strong>：</p><table tabindex="0"><thead><tr><th>動作</th><th>發生什麼</th><th>還在收費嗎</th></tr></thead><tbody><tr><td><strong>Stop（停止）</strong></td><td>關機，保留根磁碟與資料，可再開機</td><td>運算費停收，<strong>但 EBS 磁碟仍收費</strong></td></tr><tr><td><strong>Reboot（重開機）</strong></td><td>重新開機，資料與設定不變</td><td>照常</td></tr><tr><td><strong>Hibernate（休眠）</strong></td><td>把記憶體內容存到 EBS，下次開機回到原狀態</td><td>EBS 仍收費</td></tr><tr><td><strong>Terminate（終止）</strong></td><td>刪除執行個體，預設一併刪掉根 EBS</td><td>運算停收，<strong>但殘留資源可能還在收費</strong></td></tr></tbody></table><blockquote><ul><li><strong>Stop 不等於不收費</strong>——它像「熄火但車還停在收費停車場」，EBS 磁碟持續計費。真的不用了要 <strong>Terminate</strong>，而且 Terminate 也<strong>不一定清乾淨</strong>：額外的 EBS、快照、Elastic IP、負載平衡器都可能殘留繼續收費。練習完務必回頭檢查並刪除。</li><li><strong>EC2 需要儲存</strong>：每台 EC2 都有一顆<strong>根磁碟（通常是 EBS）</strong>，你的資料存在上面。</li></ul></blockquote><hr><h2 id="與-aws-互動的方式" tabindex="-1">與 AWS 互動的方式 <a class="header-anchor" href="#與-aws-互動的方式" aria-label="Permalink to &quot;與 AWS 互動的方式&quot;">​</a></h2><blockquote><p><strong>在 AWS 上做的每一件事，本質都是一個 API 呼叫</strong></p></blockquote><p>差別只在「你用什麼方式發出這個呼叫」。</p><table tabindex="0"><thead><tr><th>方式</th><th>是什麼</th><th>適合</th></tr></thead><tbody><tr><td><strong>管理主控台（Management Console）</strong></td><td>網頁圖形介面，點選操作</td><td>初學、手動操作、視覺化探索</td></tr><tr><td><strong>CLI（命令列介面）</strong></td><td>用指令操作，可寫成腳本</td><td>自動化、重複性操作</td></tr><tr><td><strong>SDK</strong></td><td>在你的程式碼裡呼叫 AWS（Python、Java…）</td><td>應用程式直接整合 AWS</td></tr><tr><td><strong>CloudFormation</strong></td><td><strong>基礎設施即程式碼（IaC）</strong>：用範本宣告要哪些資源</td><td>可重複、一致地部署整套環境</td></tr><tr><td><strong>Elastic Beanstalk</strong></td><td>你給程式碼與設定，它幫你自動佈建 EC2 / ELB / Auto Scaling</td><td>不想手動拼裝基礎設施</td></tr></tbody></table><blockquote><p>「點選的網頁介面」→ Console；「可寫腳本自動化」→ CLI；「用範本重複部署、基礎設施即程式碼」→ <strong>CloudFormation</strong>。</p></blockquote><h2 id="ec2-計費" tabindex="-1">EC2 計費 <a class="header-anchor" href="#ec2-計費" aria-label="Permalink to &quot;EC2 計費&quot;">​</a></h2><p>同一台機器，<strong>怎麼付錢</strong>有五種選擇，差別在「<strong>有沒有事先承諾</strong>」與「<strong>能不能被收回</strong>」：</p><table tabindex="0"><thead><tr><th>計費方式</th><th>怎麼算</th><th>折扣</th><th>適合</th></tr></thead><tbody><tr><td><strong>On-Demand（隨需）</strong></td><td>用多少付多少，<strong>無承諾</strong></td><td>無</td><td>短期、不可預測、開發測試</td></tr><tr><td><strong>Savings Plans（節省方案）</strong></td><td>承諾 <strong>1 或 3 年</strong>的固定用量（以 $/小時計）</td><td>大</td><td>用量穩定、想省錢又保留彈性</td></tr><tr><td><strong>Reserved Instances（預留執行個體）</strong></td><td>承諾 <strong>1 或 3 年</strong>特定規格</td><td>大</td><td>長期穩定、可預測的負載</td></tr><tr><td><strong>Spot Instances（競價執行個體）</strong></td><td>用 AWS 的<strong>閒置容量</strong></td><td>最高約 <strong>90%</strong></td><td><strong>可中斷</strong>的工作：批次、無狀態、容錯</td></tr><tr><td><strong>Dedicated Hosts（專屬主機）</strong></td><td>整台<strong>實體主機</strong>專屬給你，可看到主機 ID、sockets / cores</td><td>—</td><td><strong>BYOL</strong>（自帶授權）或法規要求掌握實體硬體資訊</td></tr></tbody></table><blockquote><ul><li><p>Spot 最便宜，但 <strong>AWS 需要容量時會把它收回</strong>（給你約 <strong>2 分鐘</strong>警告）。所以<strong>只放可以被中斷、之後能重跑的工作</strong>——絕對不要把「不能中斷的關鍵服務」放在 Spot 上。</p></li><li><p><strong>Savings Plans vs Reserved</strong>：兩者都是「承諾換折扣」。Savings Plans 較有彈性（承諾的是金額 / 用量）；Reserved 綁較死（承諾特定規格）。</p></li><li><p><strong>Dedicated Instances vs Dedicated Hosts</strong>：兩者的硬體都不和<strong>其他客戶</strong>共用。差別在於：Dedicated Instances 由 AWS 管理主機放置，你看不到底層實體機器；Dedicated Hosts 把整台實體主機交給你，你能看到 socket / core 數量、控制執行個體放哪台主機——這是 <strong>BYOL（Bring Your Own License，自帶授權）</strong> 的必要條件，因為 Windows Server、SQL Server 等授權是依實體 socket / core 計費。</p></li><li><p>🚨 看到「BYOL / 把現有軟體授權帶到 AWS」→ <strong>Dedicated Hosts</strong>；只是要「實體隔離但不在意哪台主機」→ <strong>Dedicated Instances</strong>（較便宜）。</p></li></ul></blockquote><h2 id="ec2-auto-scaling" tabindex="-1">EC2 Auto Scaling <a class="header-anchor" href="#ec2-auto-scaling" aria-label="Permalink to &quot;EC2 Auto Scaling&quot;">​</a></h2><p>Auto Scaling 讓 EC2 <strong>依需求自動增減數量</strong>。這直接呼應雲端的「不必預估容量」：傳統機房得照<strong>尖峰</strong>常備一堆平常閒置的機器；Auto Scaling 則是<strong>流量大自動加機器、流量小自動移除</strong>，省錢又不當機。</p><blockquote><p><strong>水平擴展 vs 垂直擴展</strong>：Auto Scaling 做的是<strong>水平擴展（scale out，加減機器數量）</strong>，不是把單一台機器升級成更強的（垂直擴展 scale up）。</p><table tabindex="0"><thead><tr><th></th><th>垂直（升級單機）</th><th>水平（加減機器）</th></tr></thead><tbody><tr><td>規模上限</td><td>有天花板</td><td>近乎無上限</td></tr><tr><td>升級時</td><td>通常要停機</td><td>不停機</td></tr><tr><td>故障風險</td><td>單點故障，一掛全倒</td><td>個別機器掛了還有別台</td></tr></tbody></table></blockquote><p><strong>兩種擴展策略：</strong></p><table tabindex="0"><thead><tr><th>策略</th><th>說明</th></tr></thead><tbody><tr><td><strong>動態擴展（Dynamic）</strong></td><td>依<strong>當下</strong>指標（如 CPU 使用率）即時增減</td></tr><tr><td><strong>預測擴展（Predictive）</strong></td><td>依<strong>歷史模式預測</strong>未來需求，提前準備</td></tr></tbody></table><p>設定時會定義三個值：<strong>最小（minimum）／期望（desired）／最大（maximum）</strong> 數量——確保至少有幾台、平常維持幾台、最多長到幾台。</p><h2 id="elastic-load-balancing-elb" tabindex="-1">Elastic Load Balancing（ELB） <a class="header-anchor" href="#elastic-load-balancing-elb" aria-label="Permalink to &quot;Elastic Load Balancing（ELB）&quot;">​</a></h2><p>ELB 是託管的負載平衡器，把進來的流量<strong>平均分配到多台 EC2</strong>，並且只把流量導向<strong>健康的</strong>機器。為什麼「健康檢查」這麼重要？因為若有一台 EC2 當掉了、ELB 卻還傻傻把流量送過去，那些使用者就會收到錯誤。健康檢查讓 ELB 持續探測每台機器，<strong>自動跳過故障的那台</strong>，使用者完全無感——這正是高可用的關鍵一環。</p><p><strong>為什麼 ELB 和 Auto Scaling 是天生一對：</strong> Auto Scaling 負責「該有幾台機器」，ELB 負責「流量怎麼平均分到這些機器」。機器增加時，ELB 自動把新機器納入分流；機器移除或故障時，ELB 自動把它從分流名單拿掉。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>              使用者流量</span></span>
<span class="line"><span>                  ↓</span></span>
<span class="line"><span>    Elastic Load Balancing（只分流到健康的機器）</span></span>
<span class="line"><span>       ↓            ↓            ↓</span></span>
<span class="line"><span>     EC2          EC2          EC2       ← Auto Scaling 群組</span></span>
<span class="line"><span> （流量大 → 自動加機器；流量小 → 自動移除）</span></span></code></pre></div><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><p><strong>VM vs 容器（Container）</strong></p><ul><li><a href="https://learn.microsoft.com/zh-tw/virtualization/windowscontainers/about/containers-vs-vm" target="_blank" rel="noreferrer">Microsoft Learn：容器與虛擬機</a></li><li><a href="https://ithelp.ithome.com.tw/articles/10198264" target="_blank" rel="noreferrer">iThome：淺談虛擬機（VM）與容器（Container）之差異</a></li><li><a href="https://aws.amazon.com/compare/the-difference-between-containers-and-virtual-machines/" target="_blank" rel="noreferrer">AWS：Containers vs. VMs</a></li></ul></li><li><p><strong>Hypervisor Type 1 vs Type 2</strong></p><ul><li><a href="https://www.purestorage.com/tw/knowledge/type-1-vs-type-2-hypervisor.html" target="_blank" rel="noreferrer">Pure Storage：類型 1 與類型 2 Hypervisor</a></li><li><a href="https://aws.amazon.com/compare/the-difference-between-type-1-and-type-2-hypervisors/" target="_blank" rel="noreferrer">AWS：Type 1 vs Type 2 Hypervisors</a></li></ul></li><li><p><strong>負載平衡演算法（round-robin、least-connections…）</strong></p><ul><li><a href="https://vocus.cc/article/683fffddfd8978000141acb6" target="_blank" rel="noreferrer">vocus：負載平衡 Load Balancing</a></li><li><a href="https://ithelp.ithome.com.tw/articles/10364142" target="_blank" rel="noreferrer">iThome 鐵人賽：負載均衡技術</a></li></ul></li></ul><hr><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>EC2</strong> = 雲上可調整大小的虛擬伺服器；幾分鐘開好、用多少付多少；底層用虛擬化做多租戶隔離</li><li><strong>執行個體類別</strong>：General Purpose（均衡）、Compute Optimized（高 CPU）、Memory Optimized（大記憶體）、Storage Optimized（高速本地儲存）、Accelerated Computing（GPU）</li><li><strong>開機三要素</strong>：AMI（系統映像）、Key Pair（SSH 金鑰）、Security Group（防火牆，需手動開 port）</li><li><strong>佈建方式</strong>：Console（網頁手動）、CLI（腳本）、SDK（程式碼）、<strong>CloudFormation（IaC、可重複部署）</strong>、Elastic Beanstalk（自動佈建）</li><li><strong>計費</strong>：On-Demand（無承諾最彈性）、Savings Plans / Reserved（承諾 1–3 年換折扣）、Spot（閒置容量最省約 90%、<strong>可被收回</strong>）、Dedicated Hosts（專屬實體機、為法規 / 授權）</li><li><strong>水平 vs 垂直</strong>：垂直有天花板 + 要停機 + 單點故障；水平近乎無上限 + 高可用——雲端偏好水平</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>短期、不可預測、開發測試的負載</td><td><strong>On-Demand</strong></td></tr><tr><td>長期穩定、可預測、想省錢</td><td><strong>Savings Plans / Reserved Instances</strong></td></tr><tr><td>可中斷的批次工作、要最省錢</td><td><strong>Spot Instances</strong></td></tr><tr><td>法規 / 軟體授權要求專屬實體主機</td><td><strong>Dedicated Hosts</strong></td></tr><tr><td>流量起伏大，要自動增減機器</td><td><strong>EC2 Auto Scaling</strong></td></tr><tr><td>把流量平均分配到多台健康主機</td><td><strong>Elastic Load Balancing</strong></td></tr><tr><td>用範本可重複部署整套基礎設施</td><td><strong>CloudFormation（IaC）</strong></td></tr><tr><td>需要大記憶體跑記憶體內資料庫</td><td><strong>Memory Optimized</strong> 執行個體</td></tr></tbody></table>`,45)])])}const u=r(a,[["render",e]]);export{p as __pageData,u as default};
